SELECT affiliation, expertise, COUNT(*) AS evaluator_count
FROM evaluators
GROUP BY affiliation, expertise;

SELECT affiliation, COUNT(evaluator_id) as NumberOfEvaluators, COUNT(DISTINCT expertise) as NumberOfExpertise
FROM evaluators
GROUP BY affiliation;

SELECT evaluator_name 
FROM evaluators 
WHERE expertise IN ('Red wine blends', 'White wine varietals') AND evaluator_id > 0;

SELECT contact_email 
FROM evaluators 
WHERE evaluator_id = 1;

SELECT evaluator_name, expertise 
FROM evaluators 
WHERE affiliation LIKE 'Interna%';

SELECT DISTINCT QUOTE(expertise) 
FROM evaluators 
WHERE evaluator_id IN (0, 1);

SELECT evaluator_name, affiliation, contact_email 
FROM evaluators
WHERE affiliation IN ('Wine Appreciation Society', 'International Sommelier Association');

SELECT evaluator_name
FROM evaluators
WHERE evaluator_id = (SELECT MAX(evaluator_id) FROM evaluators);

SELECT evaluator_name, expertise, RANK() OVER (ORDER BY expertise ASC) AS expertise_rank
FROM evaluators
ORDER BY expertise_rank;
